        if (error) {
          next();
        }
      });
    });
  }

  return {
    app,
    httpServer,
    io,
    roomManager,
    start: (port: number) =>
      new Promise((resolve) => {
        httpServer.listen(port, () => resolve(httpServer));
      }),
    stop: () =>
      new Promise((resolve, reject) => {
        io.close(() => {
          httpServer.close((error) => {
            if (error) {
              reject(error);
              return;
            }
            resolve();
          });
        });
      }),
  };
}

